import {useEffect} from "react";
import {Col, Container, ProgressBar, Row, Spinner, Table} from "react-bootstrap";
import VHModal from "@core/Presentation/Components/molecules/VHModal/VHModal";
import {useTranslation} from "react-i18next";
import ErrorBox from "@core/Presentation/Components/atoms/ErrorBox/ErrorBox";
import PrimaryButton from "@core/Presentation/Components/atoms/PrimaryButton/PrimaryButton";
import {NotificationVariant} from "@core/Domain/Notifications/INotificationProvider";
import {UseToast} from "@core/Presentation/Hooks/UseToast";
import {
    CreateRecordingEntity,
    RecordingTier,
    RecordingType
} from "@admin/recordings/Domain/Entities/CreateRecordingEntity";
import {RecordingsErrors} from "@admin/recordings/Domain/Errors/RecordingsErrors";
import UseUploadRecording from "@admin/recordings/Presentation/Hooks/UseUploadRecording";
import UseGetRecordings from "@admin/recordings/Presentation/Hooks/UseGetRecordings";
import UseDeleteRecording from "@admin/recordings/Presentation/Hooks/UseDeleteRecording";
import CreateRecordingForm from "@admin/recordings/Presentation/Components/CreateRecordingForm/CreateRecordingForm.tsx";
import "./RecordingsPage.scss";
import AppLoader from "@core/Presentation/Components/molecules/AppLoader/AppLoader.tsx";

export default function RecordingsPage() {
    const {t} = useTranslation();
    const {ShowNotification} = UseToast();
    const {UploadRecording, recordingID, uploadProgress, loading, error, validationErrors} = UseUploadRecording();
    const {recordings, loading: listLoading, error: listError, refetch} = UseGetRecordings();
    const {DeleteRecording, loading: deleteLoading} = UseDeleteRecording();

    useEffect(() => {
        if (!recordingID) return;
        ShowNotification(
            t("pages.admin.recordings.messages.success_title"),
            t("pages.admin.recordings.messages.success_content"),
            NotificationVariant.Success,
        );
        refetch();
    }, [recordingID, ShowNotification, t]);

    useEffect(() => {
        if (!error) return;
        ShowNotification(
            t("pages.admin.recordings.messages.error_title"),
            t(`errors.recordings.${error}`),
            NotificationVariant.Error,
        );
    }, [error, ShowNotification, t]);

    const getDomainErrorMessage = (errorCode: RecordingsErrors | null): string | null => {
        if (!errorCode) return null;
        return t(`errors.recordings.${errorCode}`);
    };

    const handleSubmit = async (event: React.FormEvent<HTMLFormElement>): Promise<void> => {
        event.preventDefault();
        const formData = new FormData(event.currentTarget);
        const file = formData.get("File");
        const typeStr = formData.get("Type") as string;
        const typeValue = typeStr !== "" ? (Number(typeStr) as RecordingType) : null;
        const tierStr = formData.get("Tier") as string;
        const tierValue = tierStr !== "" ? (Number(tierStr) as RecordingTier) : null;

        const data: CreateRecordingEntity = {
            Name: (formData.get("Name") as string) ?? "",
            Description: (formData.get("Description") as string) ?? "",
            Type: typeValue ?? RecordingType.MEDITACION,
            Tier: tierValue ?? RecordingTier.FREE,
            File: file instanceof File && file.size > 0 ? file : null,
        };

        await UploadRecording(data);
    };

    const handleDelete = async (id: string): Promise<void> => {
        if (!window.confirm(t("pages.admin.recordings.list.delete_confirm"))) return;
        const success = await DeleteRecording(id);
        if (success) {
            ShowNotification(
                t("pages.admin.recordings.list.delete_success_title"),
                t("pages.admin.recordings.list.delete_success_content"),
                NotificationVariant.Success,
            );
        } else {
            ShowNotification(
                t("pages.admin.recordings.messages.error_title"),
                t(`errors.recordings.${RecordingsErrors.DELETE_FAILED}`),
                NotificationVariant.Error,
            );
        }
    };

    const getTypeName = (type: RecordingType): string => {
        switch (type) {
            case RecordingType.MEDITACION:
                return t("pages.admin.recordings.form.types.meditacion");
            case RecordingType.MASTERCLASS:
                return t("pages.admin.recordings.form.types.masterclass");
            case RecordingType.TALLER:
                return t("pages.admin.recordings.form.types.taller");
            default:
                return String(type);
        }
    };

    const getTierName = (tier: RecordingTier): string => {
        switch (tier) {
            case RecordingTier.FREE:
                return t("pages.admin.recordings.form.tiers.free");
            case RecordingTier.PREMIUM:
                return t("pages.admin.recordings.form.tiers.premium");
            default:
                return String(tier);
        }
    };

    return (
        <>
            <VHModal show={loading} backdrop="static" keyboard={false} centered>
                <VHModal.Header>
                    <VHModal.Title>{t("pages.admin.recordings.upload_modal.title")}</VHModal.Title>
                </VHModal.Header>
                <VHModal.Body>
                    <p className="mb-3">{t("pages.admin.recordings.upload_modal.description")}</p>
                    <ProgressBar animated now={uploadProgress} label={`${uploadProgress}%`}/>
                </VHModal.Body>
            </VHModal>

            <Container fluid className="py-4 py-md-5 recordings-page">
                <section className="vh-surface-card mb-4 recordings-page__header">
                    <h1>{t("pages.admin.recordings.title")}</h1>
                    <p>{t("pages.admin.recordings.description")}</p>
                </section>

                <Row className="g-4 align-items-start">
                    <Col lg={4} className="recordings-page__form-col">
                        <CreateRecordingForm
                            onSubmit={handleSubmit}
                            loading={loading}
                            error={error}
                            validationErrors={validationErrors}
                        />
                    </Col>

                    <Col lg={8}>
                        <section className="vh-surface-card recordings-page__list-panel">
                            <h2 className="h4">{t("pages.admin.recordings.list.title")}</h2>
                            <p className="recordings-page__panel-copy">{t("pages.admin.recordings.list.description")}</p>


                            <ErrorBox message={getDomainErrorMessage(listError)}/>

                            {listLoading ? (
                                <AppLoader message={t("pages.admin.recordings.list.loading")}/>
                            ) : (
                                <Table responsive hover>
                                    <thead>
                                    <tr>
                                        <th>{t("pages.admin.recordings.list.columns.name")}</th>
                                        <th>{t("pages.admin.recordings.list.columns.description")}</th>
                                        <th>{t("pages.admin.recordings.list.columns.type")}</th>
                                        <th>{t("pages.admin.recordings.list.columns.tier")}</th>
                                        <th>{t("pages.admin.recordings.list.columns.created")}</th>
                                        <th>{t("pages.admin.recordings.list.columns.actions")}</th>
                                    </tr>
                                    </thead>
                                    <tbody>
                                    {recordings.length === 0 ? (
                                        <tr>
                                            <td colSpan={6}>{t("pages.admin.recordings.list.empty")}</td>
                                        </tr>
                                    ) : (
                                        recordings.map((recording) => (
                                            <tr key={recording.Id}>
                                                <td>{recording.Name}</td>
                                                <td>{recording.Description}</td>
                                                <td>{getTypeName(recording.Type)}</td>
                                                <td>{getTierName(recording.Tier)}</td>
                                                <td>{new Date(recording.Created).toLocaleDateString("es-ES")}</td>
                                                <td>
                                                    <PrimaryButton
                                                        variant="dark-outline"
                                                        disabled={deleteLoading}
                                                        label={deleteLoading
                                                            ? t("pages.admin.recordings.list.deleting_button")
                                                            : t("pages.admin.recordings.list.delete_button")
                                                        }
                                                        onClick={() => handleDelete(recording.Id)}
                                                    />
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                    </tbody>
                                </Table>
                            )}
                        </section>
                    </Col>
                </Row>
            </Container>
        </>
    );
}

import {useEffect} from "react";
import {Col, Container, ProgressBar, Row} from "react-bootstrap";
import VHModal from "@core/Presentation/Components/molecules/VHModal/VHModal";
import {useTranslation} from "react-i18next";
import PrimaryButton from "@core/Presentation/Components/atoms/PrimaryButton/PrimaryButton";
import {NotificationVariant} from "@core/Domain/Notifications/INotificationProvider";
import {UseToast} from "@core/Presentation/Hooks/UseToast";
import {
    CreateRecordingEntity,
    RecordingTier,
    RecordingType
} from "@admin/recordings/Domain/Entities/CreateRecordingEntity";
import {RecordingsErrors} from "@admin/recordings/Domain/Errors/RecordingsErrors";
import UseUploadRecording from "@admin/recordings/Presentation/Hooks/UseUploadRecording";
import UseGetRecordings from "@admin/recordings/Presentation/Hooks/UseGetRecordings";
import UseDeleteRecording from "@admin/recordings/Presentation/Hooks/UseDeleteRecording";
import CreateRecordingForm from "@admin/recordings/Presentation/Components/CreateRecordingForm/CreateRecordingForm.tsx";
import RecordingList from "@admin/recordings/Presentation/Components/RecordingList/RecordingList.tsx";
import "./RecordingsPage.scss";

export default function RecordingsPage() {
    const {t} = useTranslation();
    const {ShowNotification} = UseToast();
    const {UploadRecording, recordingID, uploadProgress, loading, error, validationErrors} = UseUploadRecording();
    const {recordings, loading: listLoading, error: listError, refetch} = UseGetRecordings();
    const {DeleteRecording, loading: deleteLoading} = UseDeleteRecording();

    useEffect(() => {
        if (!recordingID) return;
        ShowNotification(
            t("pages.admin.recordings.messages.success_title"),
            t("pages.admin.recordings.messages.success_content"),
            NotificationVariant.Success,
        );
        refetch();
    }, [recordingID, ShowNotification, t]);

    useEffect(() => {
        if (!error) return;
        ShowNotification(
            t("pages.admin.recordings.messages.error_title"),
            t(`errors.recordings.${error}`),
            NotificationVariant.Error,
        );
    }, [error, ShowNotification, t]);

    const handleSubmit = async (event: React.FormEvent<HTMLFormElement>): Promise<void> => {
        event.preventDefault();
        const formData = new FormData(event.currentTarget);
        const file = formData.get("File");
        const typeStr = formData.get("Type") as string;
        const typeValue = typeStr !== "" ? (Number(typeStr) as RecordingType) : null;
        const tierStr = formData.get("Tier") as string;
        const tierValue = tierStr !== "" ? (Number(tierStr) as RecordingTier) : null;

        const data: CreateRecordingEntity = {
            Name: (formData.get("Name") as string) ?? "",
            Description: (formData.get("Description") as string) ?? "",
            Type: typeValue ?? RecordingType.MEDITACION,
            Tier: tierValue ?? RecordingTier.FREE,
            File: file instanceof File && file.size > 0 ? file : null,
        };

        await UploadRecording(data);
    };

    const handleDelete = async (id: string): Promise<void> => {
        if (!window.confirm(t("pages.admin.recordings.list.delete_confirm"))) return;
        const success = await DeleteRecording(id);
        if (success) {
            ShowNotification(
                t("pages.admin.recordings.list.delete_success_title"),
                t("pages.admin.recordings.list.delete_success_content"),
                NotificationVariant.Success,
            );
        } else {
            ShowNotification(
                t("pages.admin.recordings.messages.error_title"),
                t(`errors.recordings.${RecordingsErrors.DELETE_FAILED}`),
                NotificationVariant.Error,
            );
        }
    };

    return (
        <>
            <VHModal show={loading} backdrop="static" keyboard={false} centered>
                <VHModal.Header>
                    <VHModal.Title>{t("pages.admin.recordings.upload_modal.title")}</VHModal.Title>
                </VHModal.Header>
                <VHModal.Body>
                    <p className="mb-3">{t("pages.admin.recordings.upload_modal.description")}</p>
                    <ProgressBar animated now={uploadProgress} label={`${uploadProgress}%`}/>
                </VHModal.Body>
            </VHModal>

            <Container fluid className="py-4 py-md-5 recordings-page">
                <section className="vh-surface-card mb-4 recordings-page__header">
                    <h1>{t("pages.admin.recordings.title")}</h1>
                    <p>{t("pages.admin.recordings.description")}</p>
                </section>

                <Row className="g-4 align-items-start">
                    <Col lg={4} className="recordings-page__form-col">
                        <CreateRecordingForm
                            onSubmit={handleSubmit}
                            loading={loading}
                            error={error}
                            validationErrors={validationErrors}
                        />
                    </Col>

                    <Col lg={8}>
                        <RecordingList
                            recordings={recordings}
                            loading={listLoading}
                            error={listError}
                            deleteLoading={deleteLoading}
                            onDelete={handleDelete}
                        />
                    </Col>
                </Row>
            </Container>
        </>
    );
}

import { Result, ResultAsync } from "neverthrow";
import { API_ERROR_MAP } from "@admin/recordings/Data/Errors/ErrorMap";
import { RecordingsApiErrors } from "@admin/recordings/Data/Errors/RecordingsApiErrors";
import RecordingsDatasource from "@admin/recordings/Data/Datasources/RecordingsDatasource";
import { CreateRecordingEntity } from "@admin/recordings/Domain/Entities/CreateRecordingEntity";
import { RecordingsErrors } from "@admin/recordings/Domain/Errors/RecordingsErrors";
import { IRecordingsRepository } from "@admin/recordings/Domain/Repositories/IRecordingsRepository";

export default class RecordingsRepositoryImpl implements IRecordingsRepository {
    constructor(private readonly Datasource: RecordingsDatasource = new RecordingsDatasource()) { }

    public async UploadRecording(data: CreateRecordingEntity): Promise<Result<string, RecordingsErrors>> {
        return ResultAsync.fromPromise(this.Datasource.UploadRecording(data), () => RecordingsErrors.GENERAL_ERROR)
            .andThen((result) => result)
            .mapErr((error) => API_ERROR_MAP[error as RecordingsApiErrors] ?? RecordingsErrors.GENERAL_ERROR);
    }
}

import { Result, ResultAsync } from "neverthrow";
import { API_ERROR_MAP } from "@admin/recordings/Data/Errors/ErrorMap";
import { RecordingsApiErrors } from "@admin/recordings/Data/Errors/RecordingsApiErrors";
import RecordingsDatasource from "@admin/recordings/Data/Datasources/RecordingsDatasource";
import { CreateRecordingEntity } from "@admin/recordings/Domain/Entities/CreateRecordingEntity";
import { RecordingEntity } from "@admin/recordings/Domain/Entities/RecordingEntity";
import { RecordingsErrors } from "@admin/recordings/Domain/Errors/RecordingsErrors";
import { IRecordingsRepository } from "@admin/recordings/Domain/Repositories/IRecordingsRepository";

export default class RecordingsRepositoryImpl implements IRecordingsRepository {
    constructor(private readonly Datasource: RecordingsDatasource = new RecordingsDatasource()) { }

    public async UploadRecording(data: CreateRecordingEntity): Promise<Result<string, RecordingsErrors>> {
        return ResultAsync.fromPromise(this.Datasource.UploadRecording(data), () => RecordingsErrors.GENERAL_ERROR)
            .andThen((result) => result)
            .mapErr((error) => API_ERROR_MAP[error as RecordingsApiErrors] ?? RecordingsErrors.GENERAL_ERROR);
    }

    public async GetRecordings(): Promise<Result<RecordingEntity[], RecordingsErrors>> {
        return ResultAsync.fromPromise(this.Datasource.GetRecordings(), () => RecordingsErrors.LIST_FAILED)
            .andThen((result) => result)
            .mapErr((error) => API_ERROR_MAP[error as RecordingsApiErrors] ?? RecordingsErrors.LIST_FAILED);
    }

    public async DeleteRecording(id: string): Promise<Result<void, RecordingsErrors>> {
        return ResultAsync.fromPromise(this.Datasource.DeleteRecording(id), () => RecordingsErrors.DELETE_FAILED)
            .andThen((result) => result)
            .mapErr((error) => API_ERROR_MAP[error as RecordingsApiErrors] ?? RecordingsErrors.DELETE_FAILED);
    }
}

